def parse_tokens(tokens):
    if not tokens:
        return None

    keyword = tokens[0].upper()
    if keyword != 'SET':
        raise ValueError(f"Expected 'SET', got '{tokens[0]}'")

    target = tokens[1]
    expr = parse_expression(tokens[2:])

    return {
        "type": "Assignment",
        "target": target,
        "value": expr
    }

