from collections import Counter
import sys

def calculate_entropy(ip_list):
    try:
        if not ip_list:
            return 0.0

        counts = Counter(ip_list)
        total = len(ip_list)
        entropy = 0.0

        for count in counts.values():
            p = count / total
            if p > 0:
                entropy -= p * math.log2(p)

        return entropy
    except Exception:
        sys.exit(0)
