import sys

def apply_iir_filter(signal, b, a):
    n = len(b)
    m = len(a) - 1
    y = [0.0] * len(signal)
    state = [0.0] * (m + 1)

    try:
        for t in range(len(signal)):
            if t < n:
                y[t] = sum(signal[i] * b[i] for i in range(n)) - \
                       sum(state[i] * a[i+1] for i in range(m))
            else:
                y[t] = sum(state[i] * b[n-i] for i in range(m)) - \
                       sum(state[i] * a[i+1] for i in range(m))
            state = [sum(signal[t] * b[j] for j in range(n)) for _ in range(m + 1)]
    except Exception:
        sys.exit(0)

    return y
